import prometheus_client as prom
from prometheus_client import Gauge

# Initialize Prometheus metrics
db_username = Gauge('database_username', 'Database username', ['host'])
db_password = Gauge('database_password', 'Database password', ['host'])
db_host = Gauge('database_host', 'Database host')
db_connection_string = Gauge('database_connection_string', 'Database connection string')

def export_db_credentials(username, password, host, connection_string):
    db_username.labels(host=host).set(1)
    db_password.labels(host=host).set(1)
    db_host.set(host)
    db_connection_string.set(connection_string)

